/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — Hosted Gateway Management
   Provision, monitor, restart, and manage per-user IB Gateway / Moomoo OpenD
   instances hosted on Aura Alpha servers.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import AnimatedPage from '../components/AnimatedPage';
import usePageTitle from '../hooks/usePageTitle';
import { api, apiPost, apiPut, apiDelete } from '../utils/api';
import { tokens } from '../styles/tokens';

const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
};
const mono = tokens.font.mono;

const STATUS_COLORS = {
  connected: C.green,
  awaiting_2fa: C.amber,
  starting: C.amber,
  disconnected: C.red,
  error: C.red,
  stopped: C.textSecondary,
  provisioned: C.blue,
};

const STATUS_LABELS = {
  connected: 'Connected',
  awaiting_2fa: 'Awaiting 2FA',
  starting: 'Starting',
  disconnected: 'Disconnected',
  error: 'Error',
  stopped: 'Stopped',
  provisioned: 'Provisioned',
};

function timeSince(dateStr) {
  if (!dateStr) return '--';
  const d = new Date(dateStr);
  const now = new Date();
  const sec = Math.floor((now - d) / 1000);
  if (sec < 60) return `${sec}s ago`;
  if (sec < 3600) return `${Math.floor(sec / 60)}m ago`;
  if (sec < 86400) return `${Math.floor(sec / 3600)}h ago`;
  return `${Math.floor(sec / 86400)}d ago`;
}

// ── Provision Form ──────────────────────────────────────────────────────
function ProvisionForm({ onProvisioned }) {
  const [gatewayType, setGatewayType] = useState('ibkr');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [accountId, setAccountId] = useState('');
  const [tradingMode, setTradingMode] = useState('paper');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleProvision = async () => {
    if (!username.trim()) { setError('Username is required'); return; }
    if (!password.trim()) { setError('Password is required'); return; }

    setLoading(true);
    setError('');
    try {
      const res = await apiPost('/gateways/provision', {
        ibkr_username: username.trim(),
        ibkr_password: password,
        ibkr_account_id: accountId.trim(),
        trading_mode: tradingMode,
        gateway_type: gatewayType,
        label: gatewayType === 'moomoo' ? 'Moomoo Gateway' : 'IBKR Gateway',
      });
      if (res?.ok) {
        onProvisioned(res);
      } else {
        setError(res?.detail || res?.error || 'Provisioning failed');
      }
    } catch (err) {
      setError(err.message || 'Provisioning failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      background: C.surface, border: `1px solid ${C.border}`, borderRadius: 12,
      padding: '2rem', maxWidth: 480,
    }}>
      <h3 style={{ color: C.textPrimary, marginBottom: '1rem', fontSize: '1.1rem' }}>
        Provision Hosted Gateway
      </h3>
      <p style={{ color: C.textSecondary, fontSize: '0.85rem', marginBottom: '1.5rem', lineHeight: 1.5 }}>
        We'll run a dedicated broker gateway on our servers for your account.
        $29/mo add-on (free for Pro+ tiers).
      </p>

      <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
        <div>
          <label style={labelStyle}>Gateway Type</label>
          <select value={gatewayType} onChange={(e) => setGatewayType(e.target.value)}
            style={inputStyle}>
            <option value="ibkr">IBKR (Interactive Brokers)</option>
            <option value="moomoo">Moomoo (OpenD)</option>
          </select>
        </div>
        <div>
          <label style={labelStyle}>
            {gatewayType === 'moomoo' ? 'Moomoo Login' : 'IBKR Username'}
          </label>
          <input value={username} onChange={(e) => setUsername(e.target.value)}
            placeholder={gatewayType === 'moomoo' ? 'Moomoo account' : 'IBKR username'}
            style={inputStyle} autoComplete="off" />
        </div>
        <div>
          <label style={labelStyle}>Password</label>
          <input type="password" value={password} onChange={(e) => setPassword(e.target.value)}
            placeholder="Encrypted at rest" style={inputStyle} autoComplete="new-password" />
        </div>
        <div>
          <label style={labelStyle}>Account ID (optional)</label>
          <input value={accountId} onChange={(e) => setAccountId(e.target.value)}
            placeholder={gatewayType === 'moomoo' ? 'e.g. 281234567' : 'e.g. U23403617'}
            style={inputStyle} />
        </div>
        <div>
          <label style={labelStyle}>Trading Mode</label>
          <div style={{ display: 'flex', gap: '1rem' }}>
            {['paper', 'live'].map(mode => (
              <label key={mode} style={{
                display: 'flex', alignItems: 'center', gap: '0.4rem',
                color: tradingMode === mode ? C.textPrimary : C.textSecondary,
                cursor: 'pointer', fontSize: '0.85rem',
              }}>
                <input type="radio" name="tm" value={mode}
                  checked={tradingMode === mode}
                  onChange={() => setTradingMode(mode)}
                  style={{ accentColor: mode === 'live' ? C.amber : C.blue }} />
                {mode === 'paper' ? 'Paper' : 'Live'}
              </label>
            ))}
          </div>
        </div>

        {error && <div style={{ color: C.red, fontSize: '0.85rem' }}>{error}</div>}

        <button onClick={handleProvision} disabled={loading}
          style={{
            ...btnStyle, background: C.blue, color: '#fff',
            opacity: loading ? 0.6 : 1, cursor: loading ? 'not-allowed' : 'pointer',
          }}>
          {loading ? 'Provisioning...' : 'Provision Gateway'}
        </button>
      </div>
    </div>
  );
}

// ── Gateway Status Card ─────────────────────────────────────────────────
function GatewayCard({ gateway, onRefresh }) {
  const [actionLoading, setActionLoading] = useState('');
  const [confirmDestroy, setConfirmDestroy] = useState(false);

  const doAction = async (action) => {
    setActionLoading(action);
    try {
      if (action === 'start') await apiPost(`/gateways/${gateway.id}/start`);
      else if (action === 'stop') await apiPost(`/gateways/${gateway.id}/stop`);
      else if (action === 'restart') await apiPost(`/gateways/${gateway.id}/restart`);
      else if (action === 'destroy') await apiDelete(`/gateways/${gateway.id}`);
      onRefresh();
    } catch { /* ignore */ }
    setActionLoading('');
    setConfirmDestroy(false);
  };

  const status = gateway.status || 'unknown';
  const statusColor = STATUS_COLORS[status] || C.textSecondary;
  const statusLabel = STATUS_LABELS[status] || status;
  const gwType = gateway.gateway_type || 'ibkr';

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
      style={{
        background: C.surface, border: `1px solid ${C.border}`, borderRadius: 12,
        padding: '1.5rem', maxWidth: 600,
      }}
    >
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
        <div>
          <h3 style={{ color: C.textPrimary, fontSize: '1.1rem', margin: 0 }}>
            {gateway.label || 'My Gateway'}
          </h3>
          <span style={{ color: C.textSecondary, fontSize: '0.8rem' }}>
            {gwType.toUpperCase()} | Port {gateway.host_port}
          </span>
        </div>
        <div style={{
          display: 'flex', alignItems: 'center', gap: '0.5rem',
          padding: '0.3rem 0.75rem', borderRadius: 20,
          background: `${statusColor}15`, border: `1px solid ${statusColor}40`,
        }}>
          <div style={{
            width: 8, height: 8, borderRadius: '50%', background: statusColor,
            boxShadow: status === 'connected' ? `0 0 8px ${statusColor}` : 'none',
          }} />
          <span style={{ color: statusColor, fontSize: '0.8rem', fontWeight: 600 }}>
            {statusLabel}
          </span>
        </div>
      </div>

      {/* Status message */}
      {gateway.status_message && (
        <p style={{
          color: status === 'error' ? C.red : C.textSecondary,
          fontSize: '0.85rem', margin: '0 0 1rem', lineHeight: 1.4,
        }}>
          {gateway.status_message}
        </p>
      )}

      {/* 2FA spinner */}
      {status === 'awaiting_2fa' && (
        <div style={{
          display: 'flex', alignItems: 'center', gap: '0.75rem',
          padding: '0.75rem 1rem', borderRadius: 8, marginBottom: '1rem',
          background: `${C.amber}10`, border: `1px solid ${C.amber}30`,
        }}>
          <div style={{
            width: 20, height: 20, borderRadius: '50%',
            border: `2px solid ${C.amber}`, borderTopColor: 'transparent',
            animation: 'spin 1s linear infinite',
          }} />
          <span style={{ color: C.amber, fontSize: '0.85rem' }}>
            {gwType === 'ibkr'
              ? 'Approve 2FA on your IBKR Mobile app'
              : 'Waiting for OpenD connection...'}
          </span>
          <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
        </div>
      )}

      {/* Info grid */}
      <div style={{
        display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.75rem',
        marginBottom: '1.25rem',
      }}>
        {[
          { label: 'Host Port', value: gateway.host_port },
          { label: 'Trading Mode', value: (gateway.trading_mode || 'paper').toUpperCase() },
          { label: 'Client ID Start', value: gateway.client_id_start },
          { label: 'Last Connected', value: timeSince(gateway.last_connected_at) },
        ].map(({ label, value }) => (
          <div key={label}>
            <div style={{ color: C.textSecondary, fontSize: '0.7rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
              {label}
            </div>
            <div style={{ color: C.textPrimary, fontSize: '0.9rem', fontFamily: mono }}>
              {value ?? '--'}
            </div>
          </div>
        ))}
      </div>

      {/* Actions */}
      <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
        {(status === 'stopped' || status === 'error') && (
          <ActionBtn label="Start" color={C.green} loading={actionLoading === 'start'}
            onClick={() => doAction('start')} />
        )}
        {(status === 'connected' || status === 'awaiting_2fa' || status === 'disconnected') && (
          <ActionBtn label="Stop" color={C.amber} loading={actionLoading === 'stop'}
            onClick={() => doAction('stop')} />
        )}
        {status !== 'stopped' && status !== 'provisioned' && (
          <ActionBtn label="Restart" color={C.blue} loading={actionLoading === 'restart'}
            onClick={() => doAction('restart')} />
        )}
        {!confirmDestroy ? (
          <ActionBtn label="Destroy" color={C.red}
            onClick={() => setConfirmDestroy(true)} />
        ) : (
          <div style={{ display: 'flex', gap: '0.35rem', alignItems: 'center' }}>
            <span style={{ color: C.red, fontSize: '0.8rem' }}>Confirm?</span>
            <ActionBtn label="Yes, destroy" color={C.red} loading={actionLoading === 'destroy'}
              onClick={() => doAction('destroy')} />
            <ActionBtn label="Cancel" color={C.textSecondary}
              onClick={() => setConfirmDestroy(false)} />
          </div>
        )}
      </div>
    </motion.div>
  );
}

function ActionBtn({ label, color, loading, onClick }) {
  return (
    <button onClick={onClick} disabled={loading}
      style={{
        padding: '0.4rem 0.75rem', borderRadius: 6, fontSize: '0.8rem',
        background: 'transparent', border: `1px solid ${color}50`,
        color, cursor: loading ? 'not-allowed' : 'pointer',
        opacity: loading ? 0.6 : 1,
      }}>
      {loading ? '...' : label}
    </button>
  );
}

// ── Main Page ───────────────────────────────────────────────────────────
export default function GatewayPage() {
  usePageTitle('Gateway');
  const [gateway, setGateway] = useState(null);
  const [loading, setLoading] = useState(true);
  const [noGateway, setNoGateway] = useState(false);
  const pollRef = useRef(null);

  const fetchGateway = useCallback(async () => {
    try {
      const res = await api('/gateways/me');
      if (res?.gateway) {
        setGateway(res.gateway);
        setNoGateway(false);
      } else {
        setGateway(null);
        setNoGateway(true);
      }
    } catch {
      setNoGateway(true);
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    fetchGateway();
    // Poll every 10s for status updates
    pollRef.current = setInterval(fetchGateway, 10000);
    return () => clearInterval(pollRef.current);
  }, [fetchGateway]);

  const handleProvisioned = (res) => {
    fetchGateway();
  };

  if (loading) {
    return (
      <AnimatedPage>
        <div style={{ padding: '2rem', color: C.textSecondary }}>Loading gateway status...</div>
      </AnimatedPage>
    );
  }

  return (
    <AnimatedPage>
      <div style={{ padding: '1.5rem 2rem', maxWidth: 800 }}>
        <h1 style={{ color: C.textPrimary, fontSize: '1.5rem', marginBottom: '0.5rem' }}>
          Hosted Gateway
        </h1>
        <p style={{ color: C.textSecondary, fontSize: '0.85rem', marginBottom: '1.5rem' }}>
          Manage your dedicated broker gateway instance hosted on Aura Alpha servers.
        </p>

        {gateway ? (
          <GatewayCard gateway={gateway} onRefresh={fetchGateway} />
        ) : (
          <ProvisionForm onProvisioned={handleProvisioned} />
        )}
      </div>
    </AnimatedPage>
  );
}

// ── Shared styles ───────────────────────────────────────────────────────
const labelStyle = {
  display: 'block', color: C.textSecondary, fontSize: '0.8rem',
  marginBottom: '0.3rem', textTransform: 'uppercase', letterSpacing: '0.04em',
};

const inputStyle = {
  width: '100%', padding: '0.6rem 0.75rem', borderRadius: 8,
  background: C.surface2, border: `1px solid ${C.border}`,
  color: C.textPrimary, fontSize: '0.9rem', outline: 'none',
  boxSizing: 'border-box',
};

const btnStyle = {
  padding: '0.65rem 1.25rem', borderRadius: 8, fontSize: '0.9rem',
  fontWeight: 600, border: 'none', textAlign: 'center',
};
